import { Component, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';

export type EnrollmentVm = {
  courseId: string;
  courseTitle: string;
  teacherName: string;
  progress: number;
  coverUrl: string;
};

export type SessionVm = {
  id: string;
  title: string;
  teacherName: string;
  scheduledAt: string;
  status: 'upcoming' | 'live' | 'ended';
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss']
})
export class DashboardComponent {
  isLoading = signal(true);

  private enrollmentsData = signal<EnrollmentVm[]>([
    {
      courseId: 'c1',
      courseTitle: 'Algèbre — Bases et exercices',
      teacherName: 'M. Amine',
      progress: 35,
      coverUrl: 'https://images.unsplash.com/photo-1509228468518-180dd4864904?auto=format&fit=crop&w=400&q=60'
    },
    {
      courseId: 'c2',
      courseTitle: 'Physique — Mécanique',
      teacherName: 'Mme Salma',
      progress: 12,
      coverUrl: 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&w=400&q=60'
    }
  ]);

  private sessionsData = signal<SessionVm[]>([
    {
      id: 's1',
      title: 'Correction du devoir de maths',
      teacherName: 'M. Amine',
      scheduledAt: '2026-03-22T14:00:00',
      status: 'upcoming'
    },
    {
      id: 's2',
      title: 'Physique — Cinématique',
      teacherName: 'Mme Salma',
      scheduledAt: '2026-03-22T16:00:00',
      status: 'upcoming'
    }
  ]);

  enrollments = computed(() => this.enrollmentsData());
  sessions = computed(() => this.sessionsData());

  userInitials = computed(() => 'AB');

  welcomeMessage = computed(() => {
    const hour = new Date().getHours();
    if (hour < 12) return 'Bonjour';
    if (hour < 18) return 'Bon après-midi';
    return 'Bonsoir';
  });

  stats = computed(() => ({
    coursesInProgress: this.enrollmentsData().length,
    exercises: 24,
    average: 78
  }));

  constructor(private router: Router) {
    setTimeout(() => this.isLoading.set(false), 600);
  }

  joinSession(sessionId: string) {
    this.router.navigate(['/live-sessions']);
  }

  continueCourse(courseId: string) {
    this.router.navigate(['/courses', courseId]);
  }

  exploreCourses() {
    this.router.navigate(['/courses']);
  }

  viewExams() {
    this.router.navigate(['/exams']);
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-7xl px-4">
    <!-- Loading -->
    <div *ngIf="isLoading()" class="flex items-center justify-center py-20">
      <div class="h-12 w-12 animate-spin rounded-full border-4 border-gray-200 border-t-[#1A73E8]"></div>
    </div>

    <!-- Content -->
    <div *ngIf="!isLoading()">
      <!-- Welcome Header -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 class="text-2xl font-bold text-gray-900 sm:text-3xl">
              {{ welcomeMessage() }} !
            </h1>
            <p class="mt-1 text-gray-600">Voici votre tableau de bord d'apprentissage</p>
          </div>
          <div class="flex items-center gap-3">
            <div class="flex h-12 w-12 items-center justify-center rounded-full bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] text-white font-semibold">
              {{ userInitials() }}
            </div>
            <div>
              <p class="font-medium text-gray-900">Élève Demo</p>
              <p class="text-sm text-gray-500">Étudiant</p>
            </div>
          </div>
        </div>
      </div>

      <!-- Stats Cards -->
      <div class="mb-8 grid gap-4 sm:grid-cols-3">
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Cours en cours</p>
          <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().coursesInProgress }}</p>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Exercices</p>
          <p class="mt-1 text-3xl font-bold text-gray-900">{{ stats().exercises }}</p>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <p class="text-sm text-gray-500">Moyenne</p>
          <p class="mt-1 text-3xl font-bold text-[#34A853]">{{ stats().average }}%</p>
        </div>
      </div>

      <div class="grid gap-6 lg:grid-cols-2">
        <!-- Reprendre l'apprentissage -->
        <div class="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
          <h2 class="text-lg font-semibold text-gray-900">Reprendre l'apprentissage</h2>
          <div class="mt-4 space-y-4">
            <div *ngFor="let enrollment of enrollments()" class="flex gap-4 rounded-xl border border-gray-200 p-4">
              <img [src]="enrollment.coverUrl" [alt]="enrollment.courseTitle" class="h-20 w-20 flex-shrink-0 rounded-lg object-cover" />
              <div class="flex-1 overflow-hidden">
                <h3 class="truncate font-medium text-gray-900">{{ enrollment.courseTitle }}</h3>
                <p class="text-sm text-gray-500">{{ enrollment.teacherName }}</p>
                <div class="mt-2">
                  <div class="flex justify-between text-xs text-gray-500">
                    <span>Progression</span>
                    <span>{{ enrollment.progress }}%</span>
                  </div>
                  <div class="mt-1 h-2 w-full overflow-hidden rounded-full bg-gray-100">
                    <div class="h-full rounded-full bg-gradient-to-r from-[#1A73E8] to-[#FF6D00] transition-all" [style.width.%]="enrollment.progress"></div>
                  </div>
                </div>
              </div>
              <a [routerLink]="['/courses', enrollment.courseId]" class="flex self-center rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-4 py-2 text-sm font-semibold text-white">
                Continuer
              </a>
            </div>
            <div *ngIf="enrollments().length === 0" class="py-8 text-center text-gray-500">
              Aucun cours inscrit
            </div>
          </div>
        </div>

        <!-- Prochains cours en direct -->
        <div class="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
          <h2 class="text-lg font-semibold text-gray-900">Prochains cours en direct</h2>
          <div class="mt-4 space-y-3">
            <div *ngFor="let session of sessions()" class="flex items-center justify-between rounded-xl border border-gray-200 p-4">
              <div>
                <h3 class="font-medium text-gray-900">{{ session.title }}</h3>
                <p class="text-sm text-gray-500">{{ session.teacherName }}</p>
                <p class="mt-1 text-xs text-gray-400">{{ session.scheduledAt | date:'dd/MM/yyyy HH:mm' }}</p>
              </div>
              <button class="rounded-xl border border-[#1A73E8] px-4 py-2 text-sm font-medium text-[#1A73E8] hover:bg-[#1A73E8]/5">
                Rejoindre
              </button>
            </div>
            <div *ngIf="sessions().length === 0" class="py-8 text-center text-gray-500">
              Aucun cours en direct à venir
            </div>
          </div>
        </div>
      </div>
